108→// Function to find the chat input
109→function getChatInput(): HTMLElement | null {
110→  // Gemini usually has a rich-textarea
111→  // Try multiple selectors from most specific to generic
112→  const selectors = [
113→    'rich-textarea [contenteditable="true"]',
114→    'div[contenteditable="true"][role="textbox"]',
115→    '.input-area textarea',
116→    'textarea[placeholder*="Ask"]',
117→    'textarea', // Fallback, might be dangerous
118→  ];
119→
120→  for (const selector of selectors) {
121→    // We probably want the one in the main footer/input area, not others (like edit mode)
122→    // Usually the main input is visible and larger.
123→    const els = document.querySelectorAll(selector);
124→    for (const el of Array.from(els)) {
125→      // Check if it's visible
126→      if (el.getBoundingClientRect().height > 0) {
127→        return el as HTMLElement;
128→      }
129→    }
130→  }
131→  return null;
132→}
133→
134→function countLineBreaks(raw: string): number {
135→  return (raw.match(/\n/g) || []).length;
136→}
137→
138→interface SeparatorInsertResult {
139→  inserted: boolean;
140→  insertedBreaks: number;
141→}
142→
143→function getContenteditableQuoteSeparator(): string {
144→  // Firefox + Quill contenteditable tends to render an extra visual break
145→  // for double-newline insertion, so we use a single newline separator there.
146→  return getBrowserName() === 'Firefox' ? '\n' : '\n\n';
147→}
148→
149→function getPlaceholderCandidates(input: HTMLElement): string[] {
150→  const richTextarea = input.closest('rich-textarea');
151→  const candidates = [
152→    input.getAttribute('data-placeholder'),
153→    input.getAttribute('aria-placeholder'),
154→    input.getAttribute('placeholder'),
155→    richTextarea?.getAttribute('data-placeholder'),
156→    richTextarea?.getAttribute('aria-placeholder'),
157→    richTextarea?.getAttribute('placeholder'),
158→  ];
159→
160→  return candidates.filter((value): value is string => Boolean(value)).map((value) => value.trim());
161→}
162→
163→function isChatInputEmpty(input: HTMLElement | HTMLTextAreaElement): boolean {
164→  if (input instanceof HTMLTextAreaElement) {
165→    return input.value.trim().length === 0;
166→  }
167→
168→  const rawContent = input.innerText ?? input.textContent ?? '';
169→  const trimmedContent = rawContent.trim();
170→
171→  // If visible text exists and it's not placeholder text, treat as non-empty even if
172→  // Quill's `ql-blank` class lags behind DOM updates.
173→  if (trimmedContent.length > 0) {
174→    const placeholders = getPlaceholderCandidates(input);
175→    const isPlaceholderText = placeholders.some(
176→      (placeholder) => placeholder.length > 0 && placeholder === trimmedContent,
177→    );
178→    if (!isPlaceholderText) {
179→      return false;
180→    }
181→  }
182→
183→  // Gemini currently uses Quill internals. `ql-blank` is its canonical empty marker.
184→  if (input.classList.contains('ql-blank')) {
185→    return true;
186→  }
187→
188→  return trimmedContent.length === 0;
189→}
190→
191→/**
192→ * Attempts to insert separator text via execCommand and reports whether
193→ * content changed plus how many line breaks were observed as inserted.
194→ */
195→function tryInsertQuoteSeparator(input: HTMLElement, separator: string): SeparatorInsertResult {
196→  const beforeVisible = input.innerText ?? '';
197→  const beforeRaw = input.textContent ?? '';
198→  const beforeVisibleLineBreakCount = countLineBreaks(beforeVisible);
199→  const beforeRawLineBreakCount = countLineBreaks(beforeRaw);
200→  let ok = false;
201→  try {
202→    ok = document.execCommand('insertText', false, separator);
203→  } catch {
204→    ok = false;
205→  }
206→  if (!ok) return { inserted: false, insertedBreaks: 0 };
207→
208→  const afterVisible = input.innerText ?? '';
209→  const afterRaw = input.textContent ?? '';
210→  if (afterVisible === beforeVisible && afterRaw === beforeRaw) {
211→    return { inserted: false, insertedBreaks: 0 };
212→  }
213→
214→  const visibleLineBreakDelta = countLineBreaks(afterVisible) - beforeVisibleLineBreakCount;
215→  const rawLineBreakDelta = countLineBreaks(afterRaw) - beforeRawLineBreakCount;
216→  const insertedBreaks = Math.max(0, visibleLineBreakDelta, rawLineBreakDelta);
217→  return { inserted: true, insertedBreaks };
218→}
219→
220→/**
221→ * Replace math elements in a cloned DOM tree with LaTeX text nodes.
222→ * Gemini uses `.math-inline` / `.math-block` containers with `[data-math]` children.
223→ */
224→function replaceMathWithLatex(root: DocumentFragment): void {
225→  // 1. Replace .math-inline / .math-block containers
226→  for (const container of Array.from(root.querySelectorAll('.math-inline, .math-block'))) {
227→    const dataMathEl = container.querySelector('[data-math]');
228→    const latex = dataMathEl?.getAttribute('data-math');
229→    if (latex) {
230→      const isBlock = container.classList.contains('math-block');
231→      container.replaceWith(document.createTextNode(isBlock ? `$$${latex}$$` : `$${latex}$`));
232→    }
233→  }
234→
235→  // 2. Handle any remaining [data-math] elements not inside a container
236→  for (const el of Array.from(root.querySelectorAll('[data-math]'))) {
237→    const latex = el.getAttribute('data-math');
238→    if (latex) {
239→      el.replaceWith(document.createTextNode(`$${latex}$`));
240→    }
241→  }
242→}
243→
244→/**
245→ * Extract text from a Range, preserving LaTeX math syntax.
246→ *
247→ * `Range.toString()` returns visually rendered text, which loses LaTeX
248→ * delimiters (e.g. `U∈[0,1)` instead of `$U \in [0, 1)$`). This function
249→ * clones the range contents, replaces math elements with their `$...$` /
250→ * `$$...$$` LaTeX source, then returns the resulting text.
251→ */
252→function extractTextWithLatex(range: Range): string {
253→  const fragment = range.cloneContents();
254→
255→  // Short-circuit: no math elements → use native Range.toString()
256→  if (!fragment.querySelector('.math-inline, .math-block, [data-math]')) {
257→    return range.toString();
258→  }
259→
260→  replaceMathWithLatex(fragment);
261→
262→  // Use a temporary element to get innerText (preserves newlines from block elements / <br>)
263→  const temp = document.createElement('div');
264→  temp.style.position = 'fixed';
265→  temp.style.left = '-9999px';
266→  temp.style.opacity = '0';
267→  temp.style.pointerEvents = 'none';
268→  temp.appendChild(fragment);
269→  document.body.appendChild(temp);
270→  // innerText preserves newlines from block elements / <br>; textContent is the fallback
271→  const text = temp.innerText ?? temp.textContent ?? '';
272→  temp.remove();
273→
274→  return text;
275→}
276→
277→export function startQuoteReply() {
278→  injectStyles();
279→
280→  let quoteBtn: HTMLElement | null = null;
281→  let currentSelectionRange: Range | null = null;
282→  let isInternalClick = false;
283→  let scrollRafId: number | null = null;
284→  let selectionDebounceTimer: ReturnType<typeof setTimeout> | null = null;
285→
286→  /** Update button position based on current selection range's viewport coordinates. */
287→  function updatePosition() {
288→    if (!quoteBtn || !currentSelectionRange) return;
289→
290→    const rangeRect = currentSelectionRange.getBoundingClientRect();
291→
292→    // Hide when selection is scrolled out of viewport
293→    const isOffScreen = rangeRect.bottom < 0 || rangeRect.top > window.innerHeight;
294→
295→    if (isOffScreen) {
296→      if (!quoteBtn.classList.contains(CSS_CLASSES.HIDDEN)) {
297→        quoteBtn.classList.add(CSS_CLASSES.HIDDEN);
298→      }
299→      return;
300→    }
301→
302→    if (quoteBtn.classList.contains(CSS_CLASSES.HIDDEN)) {
303→      quoteBtn.classList.remove(CSS_CLASSES.HIDDEN);
304→    }
305→
306→    // Ensure the button is visible before measuring to get actual dimensions
307→    const btnRect = quoteBtn.getBoundingClientRect();
308→
309→    // Use getClientRects to get the precise position of the first line.
310→    // This prevents the button from being pushed down by empty space in multi-line selections.
311→    const firstLineRect =
312→      typeof currentSelectionRange.getClientRects === 'function'
313→        ? currentSelectionRange.getClientRects()[0] || rangeRect
314→        : rangeRect;
315→
316→    // position: fixed uses viewport coordinates, no scrollY/X needed
317→    const top = firstLineRect.top - btnRect.height - POSITIONING.BUTTON_SELECTION_GAP_PX;
318→    const left = rangeRect.left + rangeRect.width / 2 - btnRect.width / 2;
319→
320→    // Edge protection: prevent the button from being clipped or overflowing the viewport
321→    const maxLeft = window.innerWidth - btnRect.width - POSITIONING.MIN_EDGE_OFFSET_PX;
322→
323→    quoteBtn.style.top = `${Math.max(POSITIONING.MIN_EDGE_OFFSET_PX, top)}px`;
324→    quoteBtn.style.left = `${Math.min(maxLeft, Math.max(POSITIONING.MIN_EDGE_OFFSET_PX, left))}px`;
325→  }
326→
327→  function onScrollOrResize() {
328→    if (scrollRafId) return;
329→    scrollRafId = requestAnimationFrame(() => {
330→      updatePosition();
331→      scrollRafId = null;
332→    });
333→  }
334→
335→  // Create button
336→  function createButton() {
337→    if (quoteBtn) return;
338→    quoteBtn = document.createElement('div');
339→    quoteBtn.className = `${CSS_CLASSES.BUTTON} ${CSS_CLASSES.HIDDEN}`;
340→    const text = getTranslationSync('quoteReply');
341→
342→    quoteBtn.innerHTML = `${QUOTE_ICON}<span>${text}</span>`;
343→
344→    quoteBtn.addEventListener('mousedown', (e) => {
345→      e.preventDefault();
346→      e.stopPropagation();
347→      isInternalClick = true;
348→      handleQuoteClick();
349→    });
350→
351→    document.body.appendChild(quoteBtn);
352→  }
353→
354→  function handleQuoteClick() {
355→    if (!currentSelectionRange) return;
356→    const selectedText = extractTextWithLatex(currentSelectionRange).trim();
357→    if (!selectedText) return;
358→
359→    const input = getChatInput();
360→    if (input) {
361→      expandInputCollapseIfNeeded();
362→
363→      // Format: > selection
364→      // Prepare quote body (without leading/trailing newlines - those are added at insertion time)
365→      const quoteBody = selectedText
366→        .split('\n')
367→        .map((line) => `> ${line}`)
368→        .join('\n');
369→
370→      // Ensure the input is visible
371→      input.scrollIntoView({ behavior: 'smooth', block: 'center' });
372→
373→      // Robust insertion and focus logic
374→      const performInsertion = () => {
375→        // First focus attempt
376→        input.focus();
377→
378→        // Check input state at insertion time to avoid race conditions
379→        // (user might type or another quote might be inserted during the delay)
380→        const isInputEmpty = isChatInputEmpty(input);
381→
382→        // 1. Add a newline at the end (any quote)
383→        // 2. Add a newline at the start if not the first quote
384→        // Example:
385→        // ------------
386→        // |> Quote 1 |
387→        // |New text 1|
388→        // |> Quote 2 |
389→        // |New text 2|
390→        // ------------
391→        const quoteWithTrailingNewline = `${quoteBody}\n`;
392→
393→        if (input instanceof HTMLTextAreaElement) {
394→          // Standard Textarea logic - simplified append
395→          const prefix = isInputEmpty ? '' : '\n\n';
396→          input.value += `${prefix}${quoteWithTrailingNewline}`;
397→          input.selectionStart = input.selectionEnd = input.value.length;
398→          input.dispatchEvent(new Event('input', { bubbles: true }));
399→        } else {
400→          // Contenteditable (Gemini/Quill) logic
401→          const sel = window.getSelection();
402→
403→          // For empty editors, insert from start.
404→          if (sel) {
405→            const range = document.createRange();
406→            range.selectNodeContents(input);
407→            if (isInputEmpty) {
408→              range.collapse(true);
409→            } else {
410→              range.collapse(false); // Move cursor to very end
411→            }
412→            sel.removeAllRanges();
413→            sel.addRange(range);
414→          }
415→
416→          // Try to insert a separator via execCommand in one shot.
417→          // If the command succeeds and mutates content, only the quote body
418→          // (or missing part of it) remains to be inserted.
419→          // If insertion does not mutate content, fall back to prepending separator.
420→          const quoteSeparator = getContenteditableQuoteSeparator();
421→          const requiredSeparatorBreaks = countLineBreaks(quoteSeparator);
422→          let contentToInsert: string;
423→          let forceRangeInsertion = false;
424→          if (!isInputEmpty) {
425→            const separatorResult = tryInsertQuoteSeparator(input, quoteSeparator);
426→            if (separatorResult.inserted) {
427→              const missingBreaks = Math.max(
428→                0,
429→                requiredSeparatorBreaks - separatorResult.insertedBreaks,
430→              );
431→              contentToInsert =
432→                missingBreaks > 0
433→                  ? `${'\n'.repeat(missingBreaks)}${quoteWithTrailingNewline}`
434→                  : quoteWithTrailingNewline;
435→              // Avoid re-running execCommand after partial mutation to prevent duplicate separators.
436→              forceRangeInsertion = missingBreaks > 0;
437→            } else {
438→              contentToInsert = `${quoteSeparator}${quoteWithTrailingNewline}`;
439→            }
440→          } else {
441→            contentToInsert = quoteWithTrailingNewline;
442→          }
443→
444→          // Quill handles text insertion better with native insertText command.
445→          // Fallback to manual Range insertion when command is unavailable.
446→          let inserted = false;
447→          if (!forceRangeInsertion) {
448→            try {
449→              inserted = document.execCommand('insertText', false, contentToInsert);
450→            } catch {
451→              inserted = false;
452→            }
453→          }
454→
455→          if (!inserted) {
456→            const textNode = document.createTextNode(contentToInsert);
457→            if (sel) {
458→              if (forceRangeInsertion) {
459→                const endRange = document.createRange();
460→                endRange.selectNodeContents(input);
461→                endRange.collapse(false);
462→                sel.removeAllRanges();
463→                sel.addRange(endRange);
464→              }
465→            }
466→
467→            if (sel && sel.rangeCount > 0) {
468→              const insertRange = sel.getRangeAt(0);
469→              insertRange.insertNode(textNode);
470→
471→              // Move cursor to after the inserted text
472→              insertRange.setStartAfter(textNode);
473→              insertRange.setEndAfter(textNode);
474→              sel.removeAllRanges();
475→              sel.addRange(insertRange);
476→            } else {
477→              // Fallback: just append to the input
478→              input.appendChild(textNode);
479→            }
480→          }
481→
482→          // Re-force cursor to the end after insertion
483→          const finalRange = document.createRange();
484→          finalRange.selectNodeContents(input);
485→          finalRange.collapse(false);
486→          sel?.removeAllRanges();
487→          sel?.addRange(finalRange);
488→
489→          input.dispatchEvent(new Event('input', { bubbles: true }));
490→        }
491→
492→        // Final focus force
493→        input.focus();
494→        // Some editors need an extra click or focus to show the cursor
495→        setTimeout(() => input.focus(), TIMING.FOCUS_RETRY_DELAY_MS);
496→      };
497→
498→      // Use a slightly longer delay to wait for any expansion transitions
499→      setTimeout(performInsertion, TIMING.INSERTION_DELAY_MS);
500→
501→      // Hide button and clear selection state
502→      hideButton();
503→      currentSelectionRange = null;
504→      window.getSelection()?.removeAllRanges();
505→    } else {
506→      console.warn('[Gemini Voyager] Could not find chat input.');
507→    }
508→  }
509→
510→  function showButton() {
511→    if (!quoteBtn) createButton();
512→    if (!quoteBtn) return;
513→
514→    // updatePosition() manages visibility (HIDDEN class) based on viewport check
515→    updatePosition();
516→
517→    // Add listeners for scroll/resize
518→    window.addEventListener('scroll', onScrollOrResize, { capture: true, passive: true });
519→    window.addEventListener('resize', onScrollOrResize, { passive: true });
520→  }
521→
522→  function hideButton() {
523→    if (quoteBtn) {
524→      quoteBtn.classList.add(CSS_CLASSES.HIDDEN);
525→    }
526→    // Remove listeners
527→    window.removeEventListener('scroll', onScrollOrResize, { capture: true });
528→    window.removeEventListener('resize', onScrollOrResize);
529→    if (scrollRafId) {
530→      cancelAnimationFrame(scrollRafId);
531→      scrollRafId = null;
532→    }
533→  }
534→
535→  function handleSelectionChange() {
536→    // Debounce to let selection settle and avoid redundant updates on rapid key events
537→    if (selectionDebounceTimer) clearTimeout(selectionDebounceTimer);
538→    selectionDebounceTimer = setTimeout(() => {
539→      const selection = window.getSelection();
540→      if (!selection || selection.rangeCount === 0 || selection.isCollapsed) {
541→        hideButton();
542→        currentSelectionRange = null;
543→        return;
544→      }
545→
546→      const text = selection.toString().trim();
547→      if (!text) {
548→        hideButton();
549→        currentSelectionRange = null;
550→        return;
551→      }
552→
553→      // Check if selection is within a message user/model bubble
554→      // We don't want to quote random UI elements
555→      const anchor = selection.anchorNode;
556→      if (!anchor) return;
557→
558→      const element =
559→        anchor.nodeType === Node.TEXT_NODE ? anchor.parentElement : (anchor as HTMLElement);
560→
561→      // Check if selection is inside main content area
562→      // Gemini uses <main> or sometimes specific classes. We want to avoid nav, sidebar, etc.
563→      const mainContent = document.querySelector('main');
564→      if (mainContent && !mainContent.contains(element)) {
565→        hideButton();
566→        return;
567→      }
568→
569→      // Also explicitly check for sidebar classes just in case
570→      if (
571→        element?.closest('nav') ||
572→        element?.closest('[role="navigation"]') ||
573→        element?.closest('.sidebar') ||
574→        element?.closest('.mat-drawer')
575→      ) {
576→        hideButton();
577→        return;
578→      }
579→
580→      // Selectors for valid areas: user-query-container, model-response, conversation-container
581→      // Or just check if it's not the input box itself
582→      if (element?.closest('[contenteditable="true"]')) {
583→        hideButton();
584→        return;
585→      }
586→
587→      // Also check if we are selecting code block content? Might be fine.
588→
589→      const range = selection.getRangeAt(0);
590→      currentSelectionRange = range;
591→      const rect = range.getBoundingClientRect();
592→
593→      // If rect is zero (e.g. invisible), don't show
594→      if (rect.width === 0 && rect.height === 0) return;
595→
596→      showButton();
597→    }, TIMING.SELECTION_DEBOUNCE_MS);
598→  }
599→
600→  function onMouseUp(_: MouseEvent) {
601→    if (isInternalClick) {
602→      isInternalClick = false;
603→      return;
604→    }
605→    handleSelectionChange();
606→  }
607→
608→  // Function to update button text when language changes
609→  function updateButtonText() {
610→    if (quoteBtn) {
611→      const span = quoteBtn.querySelector('span');
612→      if (span) {
613→        span.textContent = getTranslationSync('quoteReply');
614→      }
615→    }
616→  }
617→
618→  // Listen to selection changes via mouseup (often better for "finished" selection)
619→  // selectionchange event fires too often while dragging.
620→  document.addEventListener('mouseup', onMouseUp);
621→
622→  function onKeys(e: KeyboardEvent) {
623→    if (e.key === 'Shift' || e.key.startsWith('Arrow')) {
